class AppConfig:
    """Application configuration with sensible defaults."""

    DEFAULTS = {
        'app_name': 'CommandCenter',
        'host': '127.0.0.1',
        'port': 8080,
        'db_path': 'data/command_center.db',
        'log_path': 'data/logs/app.log',
        'plugin_dir': 'plugins',
    }

    def __init__(self, overrides=None):
        self._config = dict(self.DEFAULTS)
        if overrides:
            self._config.update(overrides)

    def get(self, key, default=None):
        return self._config.get(key, default)

    def set(self, key, value):
        self._config[key] = value

    def as_dict(self):
        return dict(self._config)


class SystemInfo:
    """Collects system information and tracks uptime."""

    def __init__(self):
        self._start_time = time.time()

    def get_platform(self):
        uname = platform.uname()
        return {
            'system': uname.system, 'node': uname.node,
            'release': uname.release, 'version': uname.version,
            'machine': uname.machine,
        }

    def get_memory_usage(self):
        try:
            import resource
            rss = resource.getrusage(resource.RUSAGE_SELF).ru_maxrss * 1024
        except ImportError:
            rss = os.getpid() * 1024
        return {'rss_bytes': int(rss)}

    def get_disk_usage(self, path='.'):
        usage = shutil.disk_usage(path)
        return {'total': usage.total, 'used': usage.used, 'free': usage.free}

    def get_uptime(self):
        return time.time() - self._start_time


class FileBrowser:
    """Browse and search the file system."""

    def __init__(self, start_dir='.'):
        self.current_dir = os.path.abspath(start_dir)

    def list_files(self):
        entries = []
        for entry in os.scandir(self.current_dir):
            stat = entry.stat()
            entries.append({
                'name': entry.name, 'size': stat.st_size,
                'modified': stat.st_mtime, 'is_dir': entry.is_dir(),
            })
        return entries

    def navigate(self, path):
        if path == '..':
            new_dir = os.path.dirname(self.current_dir)
        else:
            new_dir = os.path.abspath(os.path.join(self.current_dir, path))
        if not os.path.exists(new_dir):
            raise FileNotFoundError(f'Path not found: {new_dir}')
        if not os.path.isdir(new_dir):
            raise NotADirectoryError(f'Not a directory: {new_dir}')
        self.current_dir = new_dir

    def search(self, pattern):
        full = os.path.join(self.current_dir, '**', pattern)
        return glob_module.glob(full, recursive=True)

    def get_file_info(self, path):
        stat = os.stat(path)
        return {
            'name': os.path.basename(path), 'path': os.path.abspath(path),
            'size': stat.st_size, 'modified': stat.st_mtime,
            'is_dir': os.path.isdir(path),
            'extension': os.path.splitext(path)[1],
        }


class FileOperations:
    """Static methods for common file operations."""

    @staticmethod
    def copy_file(src, dst):
        shutil.copy2(src, dst)

    @staticmethod
    def move_file(src, dst):
        shutil.move(src, dst)

    @staticmethod
    def delete_file(path):
        if os.path.isdir(path):
            shutil.rmtree(path)
        else:
            os.remove(path)

    @staticmethod
    def rename_file(path, new_name):
        new_path = os.path.join(os.path.dirname(path), new_name)
        os.rename(path, new_path)


class TaskDatabase:
    """SQLite-backed task and note manager."""

    def __init__(self, db_path=':memory:'):
        self.db_path = db_path
        self._create_tables()

    def _connect(self):
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def _create_tables(self):
        conn = self._connect()
        conn.execute('''CREATE TABLE IF NOT EXISTS tasks (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL, description TEXT DEFAULT '',
            priority TEXT DEFAULT 'medium', status TEXT DEFAULT 'active',
            created_at TEXT, due_date TEXT, tags TEXT DEFAULT ''
        )''')
        conn.execute('''CREATE TABLE IF NOT EXISTS notes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL, content TEXT DEFAULT '',
            created_at TEXT, updated_at TEXT
        )''')
        conn.commit()
        conn.close()

    def add_task(self, title, description='', priority='medium', due_date=None, tags=''):
        conn = self._connect()
        cur = conn.execute(
            'INSERT INTO tasks (title, description, priority, status, created_at, due_date, tags) VALUES (?, ?, ?, ?, ?, ?, ?)',
            (title, description, priority, 'active', datetime.now().isoformat(), due_date, tags))
        conn.commit()
        task_id = cur.lastrowid
        conn.close()
        return task_id

    def update_task(self, task_id, **kwargs):
        if not kwargs:
            return
        conn = self._connect()
        set_clause = ', '.join(f'{k} = ?' for k in kwargs)
        values = list(kwargs.values()) + [task_id]
        conn.execute(f'UPDATE tasks SET {set_clause} WHERE id = ?', values)
        conn.commit()
        conn.close()

    def delete_task(self, task_id):
        conn = self._connect()
        conn.execute('DELETE FROM tasks WHERE id = ?', (task_id,))
        conn.commit()
        conn.close()

    def search_tasks(self, query):
        conn = self._connect()
        pattern = f'%{query}%'
        rows = conn.execute(
            'SELECT * FROM tasks WHERE title LIKE ? OR description LIKE ?',
            (pattern, pattern)).fetchall()
        conn.close()
        return [dict(r) for r in rows]

    def get_tasks_by_status(self, status):
        conn = self._connect()
        rows = conn.execute('SELECT * FROM tasks WHERE status = ?', (status,)).fetchall()
        conn.close()
        return [dict(r) for r in rows]

    def add_note(self, title, content=''):
        conn = self._connect()
        now = datetime.now().isoformat()
        cur = conn.execute(
            'INSERT INTO notes (title, content, created_at, updated_at) VALUES (?, ?, ?, ?)',
            (title, content, now, now))
        conn.commit()
        note_id = cur.lastrowid
        conn.close()
        return note_id

    def search_notes(self, query):
        conn = self._connect()
        pattern = f'%{query}%'
        rows = conn.execute(
            'SELECT * FROM notes WHERE title LIKE ? OR content LIKE ?',
            (pattern, pattern)).fetchall()
        conn.close()
        return [dict(r) for r in rows]


class MessageServer:
    """TCP server that accepts multiple client connections."""

    def __init__(self, host='127.0.0.1', port=0):
        self.host = host
        self.port = port
        self.clients = {}
        self._lock = threading.Lock()
        self._running = False
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._client_counter = 0

    def start(self):
        self._socket.bind((self.host, self.port))
        self._socket.listen(5)
        self._socket.settimeout(1.0)
        self.port = self._socket.getsockname()[1]
        self._running = True
        t = threading.Thread(target=self._accept_loop, daemon=True)
        t.start()

    def _accept_loop(self):
        while self._running:
            try:
                conn, addr = self._socket.accept()
                self._client_counter += 1
                cid = f'client_{self._client_counter}'
                with self._lock:
                    self.clients[cid] = conn
            except (socket.timeout, OSError):
                continue

    def stop(self):
        self._running = False
        with self._lock:
            for conn in self.clients.values():
                try:
                    conn.close()
                except OSError:
                    pass
            self.clients.clear()
        try:
            self._socket.close()
        except OSError:
            pass

    def broadcast(self, message):
        data = message.encode('utf-8') if isinstance(message, str) else message
        with self._lock:
            for cid in list(self.clients):
                try:
                    self.clients[cid].sendall(data)
                except OSError:
                    del self.clients[cid]

    def get_client_count(self):
        with self._lock:
            return len(self.clients)


class MessageBus:
    """In-process publish/subscribe message bus."""

    def __init__(self):
        self._channels = {}
        self._lock = threading.Lock()

    def subscribe(self, channel, callback):
        with self._lock:
            if channel not in self._channels:
                self._channels[channel] = []
            self._channels[channel].append(callback)

    def unsubscribe(self, channel, callback):
        with self._lock:
            if channel in self._channels:
                self._channels[channel] = [
                    cb for cb in self._channels[channel] if cb is not callback
                ]

    def publish(self, channel, message):
        with self._lock:
            callbacks = list(self._channels.get(channel, []))
        for cb in callbacks:
            cb(message)


class Protocol:
    """JSON message protocol for TCP communication."""

    @staticmethod
    def encode(data):
        return (json.dumps(data) + '\n').encode('utf-8')

    @staticmethod
    def decode(raw_bytes):
        return json.loads(raw_bytes.decode('utf-8').strip())


class CommandCenterClient:
    """Client for connecting to the Command Center server."""

    def __init__(self):
        self._socket = None
        self._connected = False
        self._messages = []
        self._subscriptions = set()

    def connect(self, host, port):
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.connect((host, port))
        self._connected = True

    def send_message(self, msg_type, data):
        msg = {'type': msg_type, 'data': data, 'timestamp': datetime.now().isoformat()}
        self._socket.sendall(Protocol.encode(msg))

    def subscribe_channel(self, channel):
        self._subscriptions.add(channel)
        if self._connected:
            self.send_message('system', {'action': 'subscribe', 'channel': channel})

    def get_messages(self):
        msgs = list(self._messages)
        self._messages.clear()
        return msgs

    def disconnect(self):
        if self._socket:
            try:
                self._socket.close()
            except OSError:
                pass
        self._connected = False


class MetricsCollector:
    """Collects and aggregates application metrics."""

    def __init__(self, max_events=1000):
        self._events = deque(maxlen=max_events)
        self._counters = Counter()
        self._gauges = {}

    def record_event(self, event_type, data=None):
        self._events.append({
            'type': event_type, 'data': data,
            'timestamp': datetime.now().isoformat(),
        })
        self._counters[event_type] += 1

    def increment_counter(self, name, amount=1):
        self._counters[name] += amount

    def set_gauge(self, name, value):
        self._gauges[name] = value

    def get_recent(self, count=10):
        return list(self._events)[-count:]

    def get_summary(self):
        return {
            'total_events': sum(self._counters.values()),
            'top_event_types': self._counters.most_common(10),
            'gauges': dict(self._gauges),
        }


class AlertManager:
    """Manages alert rules that trigger when metrics exceed thresholds."""

    def __init__(self):
        self._rules = {}

    def add_rule(self, name, metric_name, threshold, comparator='>'):
        self._rules[name] = {
            'metric_name': metric_name,
            'threshold': threshold,
            'comparator': comparator,
        }

    def clear_rule(self, name):
        self._rules.pop(name, None)

    def check_alerts(self, metrics_collector):
        gauges = metrics_collector.get_summary()['gauges']
        triggered = []
        for name, rule in self._rules.items():
            value = gauges.get(rule['metric_name'])
            if value is None:
                continue
            if rule['comparator'] == '>' and value > rule['threshold']:
                triggered.append({
                    'rule': name, 'metric': rule['metric_name'],
                    'value': value, 'threshold': rule['threshold'],
                })
            elif rule['comparator'] == '<' and value < rule['threshold']:
                triggered.append({
                    'rule': name, 'metric': rule['metric_name'],
                    'value': value, 'threshold': rule['threshold'],
                })
        return triggered


class SearchEngine:
    """Full-text search across tasks, notes, and files."""

    def __init__(self, task_db, file_browser):
        self._task_db = task_db
        self._file_browser = file_browser
        self._file_index = {}

    def build_index(self):
        text_extensions = {'.txt', '.py', '.md', '.json'}
        for root, dirs, files in os.walk(self._file_browser.current_dir):
            for fname in files:
                ext = os.path.splitext(fname)[1].lower()
                if ext in text_extensions:
                    fpath = os.path.join(root, fname)
                    try:
                        with open(fpath, 'r', encoding='utf-8', errors='ignore') as f:
                            self._file_index[fpath] = f.read()
                    except (OSError, PermissionError):
                        pass

    def search(self, query, scope=None):
        if scope is None:
            scope = ['tasks', 'notes', 'files']
        parsed = self._parse_query(query)
        results = []
        if 'tasks' in scope:
            results.extend(self._search_tasks(parsed))
        if 'notes' in scope:
            results.extend(self._search_notes(parsed))
        if 'files' in scope:
            results.extend(self._search_files(parsed))
        return results

    def _parse_query(self, query):
        parsed = {'must': [], 'should': [], 'must_not': []}
        if ' AND ' in query:
            parsed['must'] = [t.strip() for t in query.split(' AND ')]
        elif ' OR ' in query:
            parsed['should'] = [t.strip() for t in query.split(' OR ')]
        elif query.startswith('NOT '):
            parsed['must_not'] = [query[4:].strip()]
        else:
            parsed['must'] = [query.strip()]
        return parsed

    def _matches_query(self, text, parsed):
        if parsed['must']:
            if not all(re.search(t, text, re.IGNORECASE) for t in parsed['must']):
                return False
        if parsed['should']:
            if not any(re.search(t, text, re.IGNORECASE) for t in parsed['should']):
                return False
        if parsed['must_not']:
            if any(re.search(t, text, re.IGNORECASE) for t in parsed['must_not']):
                return False
        return True

    def highlight_matches(self, text, pattern):
        return re.sub(pattern, r'**\g<0>**', text, flags=re.IGNORECASE)

    def _search_tasks(self, parsed):
        results = []
        conn = self._task_db._connect()
        rows = conn.execute('SELECT * FROM tasks').fetchall()
        conn.close()
        for row in rows:
            d = dict(row)
            combined = f"{d['title']} {d['description']}"
            if self._matches_query(combined, parsed):
                results.append({'source': 'tasks', 'title': d['title'], 'match': d['description']})
        return results

    def _search_notes(self, parsed):
        results = []
        conn = self._task_db._connect()
        rows = conn.execute('SELECT * FROM notes').fetchall()
        conn.close()
        for row in rows:
            d = dict(row)
            combined = f"{d['title']} {d['content']}"
            if self._matches_query(combined, parsed):
                results.append({'source': 'notes', 'title': d['title'], 'match': d['content']})
        return results

    def _search_files(self, parsed):
        results = []
        for fpath, content in self._file_index.items():
            if self._matches_query(content, parsed):
                results.append({'source': 'files', 'name': os.path.basename(fpath), 'match': content[:200]})
        return results


