class DashboardWindow:
    """Main application window with menu bar, sidebar, content area, and status bar."""

    def __init__(self, root=None):
        if root is None:
            self.root = tk.Tk()
        else:
            self.root = root
        self.root.title('Command Center')
        self.root.columnconfigure(1, weight=1)
        self.root.rowconfigure(0, weight=1)
        self._current_panel = None
        self._create_menu_bar()
        self._create_sidebar()
        self._create_content_area()
        self._create_status_bar()

    def _create_menu_bar(self):
        self.menu_bar = tk.Menu(self.root)
        file_menu = tk.Menu(self.menu_bar, tearoff=0)
        file_menu.add_command(label='Exit', command=self.root.quit)
        self.menu_bar.add_cascade(label='File', menu=file_menu)
        view_menu = tk.Menu(self.menu_bar, tearoff=0)
        for name in ('Messages', 'Tasks', 'Files', 'System'):
            view_menu.add_command(label=name, command=lambda n=name: self.switch_panel(n))
        self.menu_bar.add_cascade(label='View', menu=view_menu)
        tools_menu = tk.Menu(self.menu_bar, tearoff=0)
        tools_menu.add_command(label='Search')
        self.menu_bar.add_cascade(label='Tools', menu=tools_menu)
        help_menu = tk.Menu(self.menu_bar, tearoff=0)
        help_menu.add_command(label='About')
        self.menu_bar.add_cascade(label='Help', menu=help_menu)
        self.root.config(menu=self.menu_bar)

    def _create_sidebar(self):
        self.sidebar = tk.Frame(self.root, width=150, bg='#2c3e50')
        self.sidebar.grid(row=0, column=0, sticky='ns')
        for name in ('Messages', 'Tasks', 'Files', 'System'):
            btn = tk.Button(self.sidebar, text=name, width=15,
                            command=lambda n=name: self.switch_panel(n))
            btn.pack(pady=2, padx=5)

    def _create_content_area(self):
        self.content_frame = tk.Frame(self.root)
        self.content_frame.grid(row=0, column=1, sticky='nsew')

    def _create_status_bar(self):
        self.status_bar = tk.Label(self.root, text='Ready', anchor='w', relief='sunken')
        self.status_bar.grid(row=1, column=0, columnspan=2, sticky='ew')

    def switch_panel(self, panel_name):
        for widget in self.content_frame.winfo_children():
            widget.destroy()
        self._current_panel = panel_name
        self.status_bar.config(text=f'Panel: {panel_name}')


class TaskPanel:
    """Interactive task management panel using tkinter."""

    def __init__(self, parent, task_db):
        self._task_db = task_db
        self.frame = tk.Frame(parent)
        self.frame.pack(fill='both', expand=True)
        self._tasks = []
        self._filter = 'all'

        # Task list
        self.task_list = tk.Listbox(self.frame, width=50, height=15)
        self.task_list.pack(side='top', fill='both', expand=True, padx=5, pady=5)

        # Form frame
        form = tk.Frame(self.frame)
        form.pack(fill='x', padx=5)
        tk.Label(form, text='Title:').grid(row=0, column=0, sticky='w')
        self.title_entry = tk.Entry(form, width=30)
        self.title_entry.grid(row=0, column=1)
        tk.Label(form, text='Description:').grid(row=1, column=0, sticky='w')
        self.desc_entry = tk.Entry(form, width=30)
        self.desc_entry.grid(row=1, column=1)
        tk.Label(form, text='Priority:').grid(row=2, column=0, sticky='w')
        self.priority_entry = tk.Entry(form, width=30)
        self.priority_entry.grid(row=2, column=1)

        # Buttons
        btn_frame = tk.Frame(self.frame)
        btn_frame.pack(fill='x', padx=5, pady=5)
        tk.Button(btn_frame, text='Add Task', command=self.add_task).pack(side='left', padx=2)
        tk.Button(btn_frame, text='Toggle Status', command=self.toggle_status).pack(side='left', padx=2)
        tk.Button(btn_frame, text='All', command=lambda: self.refresh_tasks(None)).pack(side='left', padx=2)
        tk.Button(btn_frame, text='Active', command=lambda: self.refresh_tasks('active')).pack(side='left', padx=2)
        tk.Button(btn_frame, text='Completed', command=lambda: self.refresh_tasks('completed')).pack(side='left', padx=2)

        self.refresh_tasks()

    def refresh_tasks(self, status_filter=None):
        self.task_list.delete(0, tk.END)
        if status_filter:
            self._tasks = self._task_db.get_tasks_by_status(status_filter)
        else:
            self._tasks = self._task_db.search_tasks('')
        for task in self._tasks:
            marker = '[x]' if task['status'] == 'completed' else '[ ]'
            self.task_list.insert(tk.END, f"{marker} {task['title']}")

    def add_task(self):
        title = self.title_entry.get().strip()
        desc = self.desc_entry.get().strip()
        priority = self.priority_entry.get().strip() or 'medium'
        if title:
            self._task_db.add_task(title, desc, priority)
        self.title_entry.delete(0, tk.END)
        self.desc_entry.delete(0, tk.END)
        self.priority_entry.delete(0, tk.END)
        self.refresh_tasks()

    def toggle_status(self):
        sel = self.task_list.curselection()
        if not sel:
            return
        idx = sel[0]
        task = self._tasks[idx]
        new_status = 'completed' if task['status'] == 'active' else 'active'
        self._task_db.update_task(task['id'], status=new_status)
        self.refresh_tasks()


